// Generated by OrchestKit Claude Plugin
// Created: 2026-06-11

/**
 * Spawn-depth registry (CC 2.1.172 — nested sub-agents up to 5 levels)
 *
 * SubagentStart inputs carry `agent_id` + `parent_agent_id` (CC 2.1.139),
 * but NOT the chain depth — so we derive it: record each agent's depth at
 * SubagentStart and resolve a child's depth as parent's + 1.
 *
 * Why a dedicated registry instead of subagent-spawns.jsonl: that log is
 * written at PreToolUse(Task) time, where CC may not have assigned
 * `agent_id` yet — lineage there is best-effort. SubagentStart is the
 * first point where both IDs are guaranteed, so the registry written here
 * is authoritative for depth resolution.
 *
 * Best-effort by design: all I/O errors swallow to a sane default — depth
 * telemetry must never block an agent dispatch.
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'node:fs';
import { dirname, join } from 'node:path';

const REGISTRY_REL = join('.claude', 'logs', 'agent-depth.json');

/** CC hard cap on nesting (2.1.172). */
export const MAX_SPAWN_DEPTH = 5;

/** Practical depth budget recommended by chain-patterns Pattern 9. */
export const SPAWN_DEPTH_BUDGET = 3;

/** Prune threshold: when the registry exceeds this, keep the newest half. */
const REGISTRY_MAX_ENTRIES = 400;

type DepthRegistry = Record<string, number>;

export function registryPath(projectDir: string): string {
  return join(projectDir, REGISTRY_REL);
}

function loadRegistry(projectDir: string): DepthRegistry {
  try {
    const path = registryPath(projectDir);
    if (!existsSync(path)) return {};
    const parsed = JSON.parse(readFileSync(path, 'utf8')) as unknown;
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) return {};
    const registry: DepthRegistry = {};
    for (const [key, value] of Object.entries(parsed as Record<string, unknown>)) {
      if (typeof value === 'number' && Number.isInteger(value) && value >= 1) {
        registry[key] = value;
      }
    }
    return registry;
  } catch {
    return {};
  }
}

function saveRegistry(projectDir: string, registry: DepthRegistry): void {
  try {
    const path = registryPath(projectDir);
    mkdirSync(dirname(path), { recursive: true });
    let entries = Object.entries(registry);
    if (entries.length > REGISTRY_MAX_ENTRIES) {
      // JSON object keys preserve insertion order — newest entries are last.
      entries = entries.slice(entries.length - REGISTRY_MAX_ENTRIES / 2);
    }
    writeFileSync(path, JSON.stringify(Object.fromEntries(entries)));
  } catch {
    // Best-effort — never block a dispatch on telemetry.
  }
}

/**
 * Resolve this agent's 1-based nesting depth and record it for its
 * future children. Call from a SubagentStart hook.
 *
 *   no parent           → 1 (spawned by the main loop)
 *   parent in registry  → parent depth + 1 (capped at MAX_SPAWN_DEPTH)
 *   parent unknown      → 2 (nested, ancestry rotated away or pre-upgrade)
 */
export function resolveAndRecordDepth(
  projectDir: string,
  agentId: string | undefined,
  parentAgentId: string | undefined,
): number {
  const registry = loadRegistry(projectDir);

  let depth: number;
  if (!parentAgentId) {
    depth = 1;
  } else {
    const parentDepth = registry[parentAgentId];
    depth = Math.min((parentDepth ?? 1) + 1, MAX_SPAWN_DEPTH);
  }

  if (agentId) {
    registry[agentId] = depth;
    saveRegistry(projectDir, registry);
  }

  return depth;
}
